What does this program print?

```cpp
#include <iostream>

template <typename T>
struct Box
{
    T value;
};

int main()
{
    Box<int> a{ 10 };
    Box<int> b{ 32 };
    std::cout << a.value + b.value << '\n';
    return 0;
}
```

